  ["7S5S-9"] = {name="Cirilo Naucriparos", type="Character", deck="Approach", faction="Vodacce", text="Your Mercenaries gain Brute.\n(Brutes do not count against your Crew Cap, go to the discard pile when destroyed, and are discarded from play at the end of the day.)\n\nCity Action: Engage Cirilo • Recruit target available Mercenary at this location. They lose Negotiable and have 1 cost instead of their printed value."},
  ["7S5S-90"] = {name="Lorenzo de Zepeda", type="Character", deck="Approach", faction="Castille", text="Reaction: When you announce an ability • Resolve it as if you are not the first player.\nTechnique: Reveal and replace the top card of the adversary's deck. When their next round begins, they may play it as their combat card by discarding a card. If they do not, wound them."},
  ["7S5S-91"] = {name="\"Madre\" Dolores", type="Character", deck="Approach", faction="Castille", text="City Action: Target a character at this location, or two characters instead by discarding a card • Heal a wound from each targeted character."},
  ["7S5S-92"] = {name="Makepeace Botwighte", type="Character", deck="Approach", faction="Castille", text="When a character opposing Makepeace equips a card, it gains +1 cost.\n\nCity Action: Target an opposing engaged character with equal or less [Inf] • Move them Home."},
  ["7S5S-93"] = {name="Maya de La Rioja", type="Character", deck="Approach", faction="Castille", text="Action: Move Maya to an adjacent City location. If you are not the first player, she may move to any location instead.\nTechnique:  -1 [Riposte] • The adversary discards a card. (Your combat card must have at least 1 [Riposte].)"},
  ["7S5S-94"] = {name="\"Padre\" Anibal", type="Character", deck="Approach", faction="Castille", text="During pressures, while Aníbal is at a location with one or fewer Renown, he gains +2 [Inf].\n\nCity Action: If Aníbal's location has no Renown • En garde him."},
  ["7S5S-95"] = {name="Patricia Moustakas", type="Character", deck="Approach", faction="Castille", text="While Patricia is at [The Docks], if she is en garde, she cannot be issued challenges\n\nCity Action:  If Patricia is at [The Docks] • Claim it.\nCity Action: If Patricia is at [The Docks], engage her • If you are the first player, draw a card. Otherwise, each opponent discards a card."},
  ["7S5S-96"] = {name="Ratón", type="Character", deck="Approach", faction="Castille", text="City Action: Target an adjacent enemy character equipped with attachment • Move Ratón to their location.\nTechnique: At the end of the adversary's next round, if they were not wounded during it, take control of target attachment on them and equip it to Ratón. (There are no adversaries if the challenge is refused.)"},
  ["7S5S-97"] = {name="Sanjay", type="Character", deck="Approach", faction="Castille", text="City Action: Target an opposing character • If their controller has fewer cards in hand than you, engage them.\nReaction: After an opponent discards a card due to your effect • Draw a card."},
  ["7S5S-98"] = {name="The Cat's Embargo", type="Scheme", deck="Approach", faction="Castille", text="Add Renown to 2 different.\n\nForced: End of planning, chosen opponent reveals a card at random.\nReaction: Opponent plays or discards revealed card . Gain renown."},
  ["7S5S-99"] = {name="Shifting Blame", type="Scheme", deck="Approach", faction="Castille", text="Add Renown to docks.\n\nReaction: Player discards card from your effect . Draw 1\nReaction: Opponent claims location . Add Renown to different."},
  ["BAS-1"] = {name="Benci Bommarito", type="Character", deck="Approach", faction="Vodacce", text="While Benci is opposed by two or more wounded characters, he gains +1[com].\n\nTechnique: Look at the top two cards of your deck. You may sink one or both and return the others in the same order. (Techniques do not resolve if the challenge is refused.)"},
  ["BAS-10"] = {name="Unravel the Thread", type="Risk", deck="Faction", faction="Vodacce", text="Sorcerer Reaction: When your performer reveals this card while gambling • Reveal additional cards equal to their [inf]. Their Sorceries gain +1[parry] this round.\n\nSorcerer Action: Sink up to two cards from a single discard pile. Then, draw a card and sink this card."},
  ["BAS-11"] = {name="Hans Offenheim", type="Character", deck="Approach", faction="Eisen", text="En Garde — When an opposing character recruits a Mercenary, they gain +1 cost.\n\nCity Action: Move target Mercenary at this location Home."},
  ["BAS-12"] = {name="Raven", type="Character", deck="Approach", faction="Eisen", text="While Raven has a Ranged card in her dueling line, the adversary cannot perform Maneuvers.\n\nCity Action: Engage Raven • She issues a [fin] challenge to target opposing character. Only characters with 3 [fin] or more can intervene."},
  ["BAS-13"] = {name="Tomas E Spielen", type="Character", deck="Approach", faction="Eisen", text="City Reaction: When a non-Artifact attachment equipped to your character at this location would be put into a discard pile • Equip it to your character at this location instead, paying all costs.\n\nTechnique: Destroy an attachment equipped to Tomas • +2 thrust."},
  ["BAS-14"] = {name="Forged for Battle", type="Scheme", deck="Approach", faction="Eisen", text="Add a Renown to [dock] and another location.\n\n[BAR]\n\nWhen your character issues a challenge or intervenes, you may engage a Weapon or Armor equipped to them. If you do, they gain +1[fin] for the duration of the action.\n(Can be used any number of times per day, and once per challenge or intervention.)"},
  ["BAS-15"] = {name="Through Thick and Thin", type="Scheme", deck="Approach", faction="Eisen", text="Add a Renown to two different locations.\n\n[BAR]\n\nAction: Target an uncontrolled City location • Move your Kaspar Dietrich and your Daniella Dietrich there and they each heal a wound. Then you may discard an available City Card from that location.(You must complete as much of an effect as possible.)"},
  ["BAS-16"] = {name="Drachenblut", type="Attachment", deck="Faction", faction="Eisen", text="Reaction: After a Hunter or Berserker equips this card • They heal a wound.\n\nGambling Technique: At the end of your round, each participant gains a threat."},
  ["BAS-17"] = {name="Jägerarmbrust", type="Attachment", deck="Faction", faction="Eisen", text="When the equipped character gambles, reveal an additional card.\n\nTechnique:  Engage this card • +1[thrust]. If your participant is an Academic or Hunter, the adversary discards a card."},
  ["BAS-18"] = {name="Seek Each Devil", type="Risk", deck="Faction", faction="Eisen", text="While your performer is an Academic or Hunter, this card has -1 cost.\n\nEn Garde Action: Target an enemy character at an adjacent City location • Move your performer there. Then, each other player who controls a Sorcerer or Monster there discards a card."},
  ["BAS-19"] = {name="No More Words!", type="Risk", deck="Faction", faction="Eisen", text="En Garde Action: Engage a Melee Weapon or Eisenfaust attachment equipped to your performer • They issue a [com] challenge to target opposing character."},
  ["BAS-2"] = {name="Danilo Danini", type="Character", deck="Approach", faction="Vodacce", text="Your Thugs at Home and Danilo's location gain +1[fin] and +1 Resolve.\n\nCity Action: Engage Danilo • He issues an [inf] challenge to target opposing character. If another character intervenes, wound them or draw a card."},
  ["BAS-20"] = {name="Vantage Point", type="Risk", deck="Faction", faction="Eisen", text="En Garde Reaction: When a pressure occurs at an adjacent location, if your performer is equipped with a Ranged Weapon • Target opponent applies -1 to their total. Then, wound target character at that location unless they engage."},
  ["BAS-21"] = {name="Aimée Barrere", type="Character", deck="Approach", faction="Montaigne", text="After an opponent's effect engages your other Musketeer at this location, they may en garde.\n\nEn Garde Technique: +1[thr]\n\nTechnique: Copy the effects of a Technique on your other Musketeer at this location. (Not one of their attachments.)"},
  ["BAS-22"] = {name="Axelle Hubert", type="Character", deck="Approach", faction="Montaigne", text="While you control a Duelist at this location, Axelle gains +1[fin] and +1 [inf].\n\nReaction: During a duel, after an opposing adversary announces their combat card • Your participant gains a threat. If Axelle is en garde, the adversary also gains a threat."},
  ["BAS-23"] = {name="Monet Dantès", type="Character", deck="Approach", faction="Montaigne", text="En Garde Reaction: After Monet moves to a City location • Reveal the top four cards of your deck. You may equip a revealed attachment to a character you control at this location, paying all costs. Discard any then sink the rest."},
  ["BAS-24"] = {name="Diplomatic Envoy", type="Scheme", deck="Approach", faction="Montaigne", text="Add a Renown to [forum]. Then, move your Diplomat there.\n\n[BAR]\n\nEn garde Diplomats at [forum] cannot be issued [com] challenges."},
  ["BAS-25"] = {name="No Rest for the Wicked", type="Scheme", deck="Approach", faction="Montaigne", text="Add a City Card to [baz]. Then add a Renown to a different location.\n\n[BAR]\n\nMerchant Reaction: At the end of Planning • Look at the top three cards of your deck, and an additional card for each Merchant you control. Draw two of them and sink the rest."},
  ["BAS-26"] = {name="Pompon", type="Attachment", deck="Faction", faction="Montaigne", text="May only equip to your Diplomat.\n\nReaction: When a pressure at this location would succeed by one or fewer, engage this card • It fails instead.\n\nTechnique: Engage this card • +1[par]."},
  ["BAS-27"] = {name="A Costly Accord", type="Risk", deck="Faction", faction="Montaigne", text="En Garde Diplomat Action: Target an opposing non-Leader that is en garde • They may engage. If they do not, claim this location."},
  ["BAS-28"] = {name="Depose", type="Risk", deck="Faction", faction="Montaigne", text="En Garde Musketeer Action: Target an opposing character • Move them and your performer to a City location you control, or one where you control a Leader."},
  ["BAS-29"] = {name="A Fine Addition...", type="Risk", deck="Faction", faction="Montaigne", text="En Garde Merchant Action: Take control of target attachment equipped to an opposing character and equip it to a your character at this location, paying all costs. Its last controller draws a card unless your Leader is a Villain"},
  ["BAS-3"] = {name="Desideria Colomberia", type="Character", deck="Approach", faction="Vodacce", text="En Garde City Reaction: After your Thug at this location is destroyed during a duel or by an opponent's effect, wound Desideria • Put the Thug in your hand.\n\nCity Reaction: After Desideria performs a Sorcerer ability, wound her • Draw a card."},
  ["BAS-30"] = {name="Tip the Scales", type="Risk", deck="Faction", faction="Montaigne", text="While your performer is a Scoundrel or Diplomat, this card has -1 cost.\n\nCity Action: Move your performer to an adjacent City location with more Renown.\n\nManeuver: +1[parry] or +1[thrust]"},
  ["BAS-31"] = {name="Andare de Castillo", type="Character", deck="Approach", faction="Castille", text="En Garde Reaction: When a duel occurs at this location, at the beginning of the first round • Remove one threat from your participant.\n\nTechnique: +1[riposte]. If Andare is engaged, gain Lethal."},
  ["BAS-32"] = {name="Giacinto", type="Character", deck="Approach", faction="Castille", text="Opposing Sorcerers have -1[inf].\n\nEn Garde City Action: Target an opposing character • Move Giacinto and that character to the same adjacent City location unless their controller reveals their hand and discards a card."},
  ["BAS-33"] = {name="Iago Carlos de Soldano", type="Character", deck="Approach", faction="Castille", text="While Iago is participating in a duel, he gains Pirate and Scoundrel.\n\nTechnique: +1[thr] or +1[par]. At the start of the adversary's next round, you may add a threat to Iago."},
  ["BAS-34"] = {name="Explosive Ultimatum", type="Scheme", deck="Approach", faction="Castille", text="Add a Renown to any location. If you have the fewest Renown, you move a Renown to an adjacent location instead.\n\n[BAR]\n\nCity Action: If an opponent controls this location • They may chose to lose control of it. If they do not, wound all opposing characters there."},
  ["BAS-35"] = {name="Meeting of the Minds", type="Scheme", deck="Approach", faction="Castille", text="Add a Renown to [Baz] and [For].\n\nIf you control an Academic, put your non-Revelry risk from your discard or The Locker into your hand.\n\n[BAR]\n\nReaction: When a pressure occurs at your performer's location • Add +1 to your total for each of your Academics there."},
  ["BAS-36"] = {name="Ciphered Tome", type="Attachment", deck="Faction", faction="Castille", text="May only equip to your Academic.\n\nCity Action: Engage this card • Move a Renown from this location to another City location.\n\nCity Action: Engage this card • Move your performer to another location with more Renown."},
  ["BAS-37"] = {name="Cats in Every Corner", type="Risk", deck="Faction", faction="Castille", text="En Garde Academic Action: Discard an available City Card at this location • Look at the top five cards of the City Deck. You may add one to this location, then sink the rest. Then, your performer may perform another action. (It must be performed and they must be the performer)"},
  ["BAS-38"] = {name="Panacea", type="Risk", deck="Faction", faction="Castille", text="When paying for this card, Alquimia and Discovery cards gain Wealth. (This card counts as two when discarded to pay costs. Send it to The Locker after paying costs.)\n\nAcademic City Action: En garde a target character at your performer's location. They heal a wound.\n\nAcademic Maneuver: En Garde your participant. They heal a wound."},
  ["BAS-39"] = {name="Rapsodia", type="Risk", deck="Faction", faction="Castille", text="While your performer is an Zealot, Academic, or Bard, this card has -1 cost.\n\nCity Action: Engage your performer and lose control of a City location • Claim your performer's location."},
  ["BAS-4"] = {name="Blood Money", type="Scheme", deck="Approach", faction="Vodacce", text="Add a Renown to [docks] and [bazaar]. Then, move your Duelist to a City location.\n\n[BAR]\n\nDuelist City Action: Move your performer to a location with a wounded enemy.\n\nDuelist Reaction: When an opposing character is destroyed • Draw a card."},
  ["BAS-40"] = {name="Solvente Universal", type="Risk", deck="Faction", faction="Castille", text="Academic City Action: Target an opposing equipped character • Send an attachment equipped to them to The Locker. Wound that character.\n\nAcademic Maneuver: Wound the adversary."},
  ["BAS-41"] = {name="Jak-Sen", type="Character", deck="Approach", faction="Ussura", text="When Jak-Sen's combat card is a Sorcery, gain Lethal.\n\nCity Reaction: When your character at Jak-Sen's location would be moved or engaged by an opponent's effect • Cancel that move or engage."},
  ["BAS-42"] = {name="Kaj Kousei", type="Character", deck="Approach", faction="Ussura", text="Reaction: After Kaj musters • Search the City Deck for an Artifact and equip it to your character at Home, paying all costs. (Shuffle the City Deck.)\n\nEn Garde Action: If you control an Artifact at this location • Move target opposing engaged character to a City location you do not control."},
  ["BAS-43"] = {name="Tomoe Sango", type="Character", deck="Approach", faction="Ussura", text="During a duel, Sango's adversary has -1 [fin].\n\nEn Garde Reaction: At the end of High Drama, if Sango's location is uncontrolled • Claim her location."},
  ["BAS-44"] = {name="Adrift in the Wind", type="Scheme", deck="Approach", faction="Ussura", text="Add a Renown to two different locations.\n\n[BAR]\n\nWhile your Leader is at an uncontrolled location, they gain +1 [fin].\n\nLeader Reaction: When your performer issues a challenge • Their location becomes uncontrolled."},
  ["BAS-45"] = {name="Stand Your Ground", type="Scheme", deck="Approach", faction="Ussura", text="Add a Renown to [dock] or [baz].\n\n[BAR]\n\nEn Garde Duelist Action: Your performer issues an unrefusable [com] challenge to target opposing character. When accepted, your participant gains a threat. If your adversary is destroyed during the duel, gain a Renown. (Intervening accepts the challenge)"},
  ["BAS-46"] = {name="Bravado", type="Risk", deck="Faction", faction="Ussura", text="Duelist Reaction: When your adversary's round of a duel ends • Add a threat to your Duelist participant.\n\n(The duel ends only if there is no threat remaining in any threat pool.)\n\nDuelist Maneuver: +1[parry]"},
  ["BAS-47"] = {name="Celerity", type="Risk", deck="Faction", faction="Ussura", text="Duelist City Action: Engage your performer • They issue a [fin] challenge to target opposing character. Only characters with 3[fin] or more can intervene. These effects cannot be cancelled."},
  ["BAS-48"] = {name="Iaijutsu Strike", type="Risk", deck="Faction", faction="Ussura", text="Duelist Maneuver: +1[riposte]. If this location is uncontrolled, claim it.\n\nDuelist Maneuver: +1[riposte]. If this location is controlled, it becomes uncontrolled."},
  ["BAS-49"] = {name="Point of Order", type="Risk", deck="Faction", faction="Ussura", text="City Action:Target an opposing character with lower [inf] than your performer • They may engage. If they do not, they must move to an adjacent City location."},
  ["BAS-5"] = {name="Denounced, Disgraced", type="Scheme", deck="Approach", faction="Vodacce", text="Add a Renown to [docks].\n\n[BAR]\n\nRed Hand City Action: Destroy another character you control at your performer's location • Claim this location. Each player discards a card."},
  ["BAS-50"] = {name="Severing Arc", type="Risk", deck="Faction", faction="Ussura", text="After the adversary performs a Technique, if this card is in your dueling line, they suffer a wound.\n\nDuelist Maneuver: +1[thrust]. Engage the adversary and each of their equipped attachments."},
  ["BAS-51"] = {name="A Shared Interest", type="Scheme", deck="Approach", faction="Neutral", text="Choose an opponent to add a Renown to any location. Then, add a Renown to a different location.\n\n[BAR]\n\nForced: At the end of Planning, claim a City location. Then, the chosen player claims a different City location."},
  ["BAS-52"] = {name="Motion to Delay", type="Scheme", deck="Approach", faction="Neutral", text="Choose a location with one or less renown. Add a Renown to a different location.\n\n[BAR]\n\nThe chosen location cannot be controlled.\n\nForced: At the end of High Drama • If an opponent controls more locations than you, draw a card."},
  ["BAS-53"] = {name="Leather Spaulders", type="Attachment", deck="Faction", faction="Neutral", text="May only equip to your character with 2[fin] or more.\n\nReaction: When an opponent's ability would wound the equipped character, engage this card • Ignore that wound. (The wound is not taken.)"},
  ["BAS-54"] = {name="Sabre", type="Attachment", deck="Faction", faction="Neutral", text="Technique: +1 [thr]\n\nTechnique: Engage this card • +1 [rip]"},
  ["BAS-55"] = {name="Sturdy Shield", type="Attachment", deck="Faction", faction="Neutral", text="Offhand (Offhand attachments do not count against the limit of one Armor and one Weapon per character. Limit one attachment with offhand per character.)\n\nMay only equip to your character with 2[com] or more.\n\nTechnique: Engage this card • +1[parry]\n\nGambling Technique: +1[parry]"},
  ["BAS-56"] = {name="Greed", type="Risk", deck="Faction", faction="Neutral", text="Reaction: When a Renown would be moved to or from your performer's location • Cancel the movement.\n\nEn Garde Reaction: When a player would collect Renown from your performer's location • They collect one fewer. (Even during Plunder.)"},
  ["BAS-57"] = {name="Honorable", type="Risk", deck="Faction", faction="Neutral", text="En Garde Leader Action: If you control fewer characters than an opponent • Your performer issues a challenge to target opposing non-Leader controlled by that opponent, using your choice of [com], [fin], or [inf]."},
  ["BAS-58"] = {name="Shield Rite", type="Risk", deck="Faction", faction="Neutral", text="En Garde Sorcerer Reaction: When an opponent’s ability would wound your performer • Wound target opposing character instead.\n\nSorcerer Maneuver: If the adversary is engaged • +1[riposte]. If your participant is en garde, draw a card."},
  ["BAS-59"] = {name="Silver Tongue", type="Risk", deck="Faction", faction="Neutral", text="While your performer is a Merchant or Scoundrel, this card has -1 cost.\n\nEn Garde Action: If your performer is a non-Hero • They recruit target available Mercenary at their location, paying all costs. They may parley without engaging."},
  ["BAS-6"] = {name="Assassin's Garb", type="Attachment", deck="Faction", faction="Vodacce", text="May only equip to your Duelist, Spy, or Assassin.\n\nDuring a duel, while their adversary is wounded, the equipped character gains +1[fin] and reveals an additional card when they gamble."},
  ["BAS-60"] = {name="Worldly", type="Risk", deck="Faction", faction="Neutral", text="City Action: Choose a controlled City location with no Renown or no characters • It becomes uncontrolled.\n\nManeuver: +1[thrust]. If this location is uncontrolled, +1[riposte] instead."},
  ["BAS-7"] = {name="Bernoulli's Approach", type="Risk", deck="Faction", faction="Vodacce", text="While the adversary has more wounds than your participant, this card has -1 cost.\n\nDuelist Maneuver: -3[thrust] • +2[riposte].\n\nDuelist Maneuver: -1[parry] • +2[thrust]"},
  ["BAS-8"] = {name="Fate's Silence", type="Risk", deck="Faction", faction="Vodacce", text="Forced: At the end of High Drama, if this card is equipped • Destroy it.\n\nSorcerer Strega Action: Equip this card to target opposing non-Leader. This ability cannot be copied.\n\nThe equipped character treats their text box as blank. (They cannot use any of their abilities)."},
  ["BAS-9"] = {name="Rattle the Rigging", type="Risk", deck="Faction", faction="Vodacce", text="En Garde Action: Target opponent chooses one of their characters opposing your performer. The chosen character issues a [com] challenge to your performer. If your performer is a Duelist, their first combat card gains +1[riposte]."},
  ["CU2024-0A"] = {name="Kaptain Kristian", type="Character", deck="City", faction="Neutral", text="Negotiable\n\nForced: After Kristian is recruited or sent to The Locker • All players draw a card.\n\nCity Action: Target an adjacent enemy character • Move them to Kristian's location. Their controller draws a card."},
  ["CU2024-0B"] = {name="Jesse Nkansa", type="Character", deck="City", faction="Neutral", text="Negotiable\n\nWhen Jesse issues a challenge, Villains and Scoundrels cannot refuse.\n\nExplorer City Action: Move Jesse to a location you do not control."},
  ["CU2024-0C"] = {name="Wayland Greywall", type="Character", deck="City", faction="Neutral", text="Negotiable\n\nWayland cannot equip Offhand attachments.\n\nPirate Action: Engage Wayland • Issue a [Fin] challenge to target opposing character."},
  ["CU2024-1"] = {name="Penya", type="Character", deck="City", faction="Neutral", text="Penya cannot intervene.\n\nCity Forced: When Penya participates in a duel or would be wounded • Put the top card of the City Deck at his location. Then, shuffle him into the City Deck.\n\nCity Action: Engage Penya • Move Penya and another of your characters at this location to the same adjacent City location."},
  ["CU2024-10"] = {name="Julius Caligari", type="Character", deck="City", faction="Neutral", text="Negotiable\n\nReaction: After Julius is recruited or moves to a City location • Name a Trait and target an opposing character. Then, reveal two cards at random from the hand of that character's controller. If any of the revealed cards has the named Trait, wound that character."},
  ["CU2024-12"] = {name="Equal Claim", type="Event", deck="City", faction="Neutral", text="Forced: At the end of High Drama • If each player has an equal number of characters at this location, it becomes uncontrolled."},
  ["CU2024-13"] = {name="Crabs in a Bucket", type="Event", deck="City", faction="Neutral", text="Forced: When this card is revealed • Each player with fewer Renown than the player with the most Renown draws a card.\n\nCity Action: If you have fewer Renown than target player, engage your performer • Claim this location."},
  ["CU2024-18"] = {name="Kalla and Adelheide", type="Character", deck="City", faction="Neutral", text="Negotiable\n\nReaction: After you recruit Kalla and Adelheide • Choose one: Either search your deck for an attachment, reveal it, and add it to your hand, or move them to any location and destroy target attachment equipped to an opposing character. (Shuffle your deck after searching.)"},
  ["CU2024-20"] = {name="Early Morning Arrangements", type="Event", deck="City", faction="Neutral", text="Reaction: At the end of Planning, if this card is in your Home • Move your character to an adjacent City location and discard this card.\n\nCity Action: Pressure this location with [Fin] • If successful, add a city card to this location and put this card in your Home ."},
  ["CU2024-21"] = {name="Silver Spine", type="Attachment", deck="City", faction="Neutral", text="Forced: Each Day, the first time an opponent's Risk targets the equipped character • Cancel the effects."},
  ["CU2024-3"] = {name="Chance Meeting", type="Event", deck="City", faction="Neutral", text="City Action: Target a player • In order of Initiative, each player that controls fewer characters than the targeted player may Muster a character from their approach deck at this location. Discard this card."},
  ["CU2024-5"] = {name="Devil Jonah's Bones", type="Attachment", deck="City", faction="Neutral", text="Forced: When a character equips this card • Wound them.\n\nWhen the equipped character gambles during a duel, reveal an additional card. You may reveal cards from the bottom of the deck instead of the top. If you do, cards sink to the top the of the deck instead of the bottom."},
  ["CU2024-8"] = {name="Inauguration Day", type="Event", deck="City", faction="Neutral", text="Forced: When a pressure occurs at this location • Count only the performer and en garde characters."},
  ["CU2026-1"] = {name="Penya", type="Attachment", deck="City", faction="City", text="Action: Engage this card • Move the equipped character to an adjacent City location.\n\nCity Action: Sink this card • Play target risk from an opponent's discard pile, paying all costs. After it resolves, sink it."},
  ["CU2026-11"] = {name="Let Bygones Be Bygones", type="Event", deck="City", faction="City", text="Forced: At the beginning of Dusk • Each player must choose one of their characters here. Those characters each heal a wound and do not move Home during Dusk. (Characters normally move Home during Dusk)"},
  ["CU2026-14"] = {name="Millstone Rhud", type="Character", deck="City", faction="City", text="Negotiable (You may Parley while paying for this card.)\n\nForced: After you recruit Millstone • Wound him and target opposing character.\n\nTechnique: +1[thr]\n\nTechnique: +1[thr]"},
  ["CU2026-15"] = {name="Syrneth Puzzle Box", type="Attachment", deck="City", faction="City", text="Equipped character gains Sorcerer.\n\nCity Action: Engage this card • Look at the top three cards of your deck. Sink any and replace the rest in any order. Then, you may discard a card to draw a card."},
  ["CU2026-19"] = {name="Blood in the Water", type="Event", deck="City", faction="City", text="Forced: When this card is revealed • Add a Renown to this location.\n\nForced: After a character at this location becomes engaged • Wound them."},
  ["CU2026-2"] = {name="Jack Trades", type="Character", deck="City", faction="City", text="(Mercenaries without Negotiable cannot be parleyed with.)\n\nWhile you control a Diplomat, Duelist, Pirate, or Zealot at Jack's location, he gains that trait."},
  ["CU2026-29"] = {name="Tijani", type="Character", deck="City", faction="City", text="Negotiable (You may Parley while paying for this card.)\n\nEn Garde City Action: Target an engaged character at an adjacent City location • If they have lower [fin] than Tijani, wound them.\n\n(En Garde abilities require an en garde performer.)\n\nGambling Technique: If the adversary has lower [fin] than Tijani • Wound them."},
  ["CU2026-4"] = {name="Astrid de Martinez", type="Character", deck="City", faction="City", text="Negotiable (You may Parley while paying for this card.)\n\nEn Garde — Astrid gains +1[inf] during pressures initiated by an opponent.\n\nAction: Engage Astrid • An adjacent location becomes uncontrolled. Move Astrid there."},
  ["CU2026-7"] = {name="Festival of Fools", type="Event", deck="City", faction="City", text="Forced: When this card is revealed • Each player draws a card.\n\nForced: At the end of High Drama • Each player with a character at this location that does not control this location draws a card."},
  ["CU2026-9"] = {name="Knives Out", type="Event", deck="City", faction="City", text="Characters at this location cannot refuse challenges.\n\nCity Action: Engage your performer or discard a card • Move this card to another City location. Unlimited."},
  ["FAF-1"] = {name="Cesca del Rosso", type="Character", deck="Leader", faction="Vodacce", text="At the end of Dawn, draw five cards.\n\nCity Reaction: After Cesca performs a Sorcerer ability • Wound an opposing character.\n\nCity Action: Target an opposing non-Leader • Move a wound from your Strega at this location to that character."},
  ["FAF-10"] = {name="Manipulative", type="Risk", deck="Faction", faction="Vodacce", text="Strega Reaction: After target character is mustered from an Approach deck • Wound them unless their controller returns that character to their Approach deck and musters a different character. Wound them again if you control three or more Strega."},
  ["FAF-11"] = {name="Provoking the Pack", type="Risk", deck="Faction", faction="Vodacce", text="City Action: If your performer is opposed • Move your adjacent Thug or Bodyguard to this location.\n\nGambling Maneuver: If you control a Thug or Bodyguard at this location • +1[Riposte]."},
  ["FAF-12"] = {name="Subtle ", type="Risk", deck="Faction", faction="Vodacce", text="Sorcerer Strega Reaction When your performer intervenes • The challenge becomes an [Inf] challenge. (Use [Inf] for restricted hostilities, including all current threat)"},
  ["FAF-13"] = {name="Daniella Dietrich", type="Character", deck="Leader", faction="Eisen", text="While using your abilities, characters opposing Daniella may be considered Sorcerers.(Action, Forced, Maneuver, Passive, Technique, and Reaction are abilities.)\n\nReaction: While paying for a Faith or Sorcery card • It has -1 cost.\n\nTechnique: Wound Daniella • Swap her with your Hunter or Zealot at this location."},
  ["FAF-14"] = {name="Kaspar Dietrich", type="Character", deck="Approach", faction="Eisen", text="Opponents' abilities cannot wound or move wounds to Kaspar. (Threat is still converted to wounds.)\n\nTechnique: If Kaspar is equipped with an Eisenfaust attachment or there is an Eisenfaust card in his dueling line • Wound the adversary."},
  ["FAF-15"] = {name="Joern Keitelsson", type="Character", deck="Approach", faction="Eisen", text="Forced: After Joern musters • Wound him.\n\nDuring Dusk, Joern has -3 Resolve. (Characters are destroyed when their wounds equal their Resolve)\n\nWhen Joern's challenge is refused, he heals a wound."},
  ["FAF-16"] = {name="Schwester Ise", type="Character", deck="Approach", faction="Eisen", text="During Dusk, you may choose not to move Ise Home.\n\nIse has +1 [Com] while wounded.\n\nReaction: After an enemy character moves to this location • Move another character you control to this location."},
  ["FAF-17"] = {name="Noble Sacrifice", type="Scheme", deck="Approach", faction="Eisen", text="Add a Renown to two different locations.\n\n---\n\nReaction: After your character at a City location is destroyed • Wound each opposing character at that location. Each of your characters at that location heals a wound. If the destroyed character was a Zealot, draw a card."},
  ["FAF-18"] = {name="Suffer Not the Wicked", type="Scheme", deck="Approach", faction="Eisen", text="Add a Renown to [Bazaar] and [Forums]\n\n---\n\nReaction: When a challenge issued by your Zealot or Hunter is refused • Wound the refusing character.\n\nYour wounded characters gain: \"Technique: If your adversary is a Sorcerer • +1[Thrust]\""},
  ["FAF-19"] = {name="Kaiser Schnurrbart", type="Attachment", deck="Faction", faction="Eisen", text="Equipped character gains Hunter.\n\nCity Reaction: After an opposing character moves to an adjacent City location, engage this card • Move the equipped character to their new location and engage that character."},
  ["FAF-2"] = {name="Aja", type="Character", deck="Approach", faction="Vodacce", text="City Action: Engage Aja • Issue a [Com] challenge to target opposing character. Only characters with 3[Fin] or more may intervene or refuse the challenge.\n\nGambling Technique: If the adversary is wounded • Gain Lethal."},
  ["FAF-20"] = {name="Commanding", type="Risk", deck="Faction", faction="Eisen", text="Leader Action: Target an opposing character • Move them Home.\n\nLeader Reaction: When Renown would be moved from this location • Cancel the movement."},
  ["FAF-21"] = {name="Cornered", type="Risk", deck="Faction", faction="Eisen", text="City Action: Engage your performer • They issue a [Com] challenge to target opposing Sorcerer or Monster. If they refuse, engage them. Wound any character that intervenes."},
  ["FAF-22"] = {name="Overzealous", type="Risk", deck="Faction", faction="Eisen", text="Maneuver: Final Strike • En garde target character at this location. If your participant was a Zealot or Hunter, draw a card.  (Final Strike activates if your participant is destroyed the round this card is played.)"},
  ["FAF-23"] = {name="Second Wind", type="Risk", deck="Faction", faction="Eisen", text="City Action: If your performer has two or more wounds • They heal a wound.\n\nGambling Maneuver: +1[Parry]. Your participant's threat is not converted to wounds this round unless your adversary is absent. (The threat remains for your next round.)"},
  ["FAF-24"] = {name="Superstitious", type="Risk", deck="Faction", faction="Eisen", text="Maneuver: If the adversary is a Sorcerer or Monster • +2 [Parry] or +2 [Thrust]."},
  ["FAF-25"] = {name="Angeline Dèmone", type="Character", deck="Leader", faction="Montaigne", text="After Angeline moves to a City location, wound an engaged character opposing her.\n\nTechnique: +1 [rip]\n\nGambling Technique: Move both participants to any City location. (The duel continues)"},
  ["FAF-26"] = {name="Angeline Dèmone", type="Character", deck="Approach", faction="Montaigne", text="While you control another Sorcerer at Angeline's location, she has +1 [Inf].\n\nAction: Discard a card • Move Angeline to an adjacent City location. Then, If the discarded card was a Sorcery, wound an opposing character."},
  ["FAF-27"] = {name="Odette Dubois d'Arrent", type="Character", deck="Approach", faction="Montaigne", text="City Reaction: After another character at this location is destroyed • Odette heals a wound. Then, you may move an adjacent Renown to this location.\n\nCity Reaction: After a challenge is issued at this location • Move your adjacent Duelist to this location. (Before choosing to intervene.)"},
  ["FAF-28"] = {name="Térence Rois", type="Character", deck="Approach", faction="Montaigne", text="Térence cannot issue [Com] challenges.\n\nWhile Térence is participating in a duel at [bazaar], set his [Com] as equal to his [Inf].\n\nCity Reaction: After a character equips an attachment at [Bazaar] • Draw a card."},
  ["FAF-29"] = {name="Hour of Blood", type="Scheme", deck="Approach", faction="Montaigne", text="Add a Renown to [Forums] and [Docks]\n\n---\n\nSorcerer City Action: Wound your performer • Choose one: Either move your character at any location to your performer’s location, or move your character at your performer’s location to any location."},
  ["FAF-3"] = {name="Don Constanzo Scarpa", type="Character", deck="Approach", faction="Vodacce", text="City Action: Your Thug at this location issues a [Com] challenge to target opposing character.\n\nCity Reaction: After your Thug is destroyed • Put a different Thug into play at your Home from your hand or discard pile, at -1 cost."},
  ["FAF-30"] = {name="Sworn Swords", type="Scheme", deck="Approach", faction="Montaigne", text="Add a Renown to two different locations.\n\n---\n\nDiplomat City Action: Engage your performer • Your Duelist at this location issues a [Com] challenge to target opposing character. Only Duelists may intervene. If the challenge is accepted, add a threat to your participant."},
  ["FAF-31"] = {name="Altruistic", type="Risk", deck="Faction", faction="Montaigne", text="Reaction: When an opponent's ability would wound, move, or engage your character • Your performer at that location suffers those effects instead. (If they are able)"},
  ["FAF-32"] = {name="Bloody Entrance", type="Risk", deck="Faction", faction="Montaigne", text="Sorcerer City Action: Wound your performer • Move them to any location, then they may perform another action. (It must be performed and they must be the performer of the action)"},
  ["FAF-33"] = {name="Glorious", type="Risk", deck="Faction", faction="Montaigne", text="Forced: After your adversary is destroyed, if this card is in your dueling line • Your participant heals a wound.\n\nGambling Maneuver: If your participant has equal or greater [Inf] than the adversary • Wound the adversary."},
  ["FAF-34"] = {name="La Voix des Sans Voix", type="Risk", deck="Faction", faction="Montaigne", text="Diplomat City Action: Engage your performer • En garde another character you control at this location. Then, that character may heal a wound. If they do not, draw a card."},
  ["FAF-35"] = {name="Loyal", type="Risk", deck="Faction", faction="Montaigne", text="Reaction: When a pressure occurs, if you control more non-Mercenaries at that location than each opponent • Add +1 to your total for the pressure.\n\nManeuver: Wound your other character at this location • +1[Riposte] or +2[Thrust]."},
  ["FAF-36"] = {name="Valroux Exemplar", type="Risk", deck="Faction", faction="Montaigne", text="If your participant has more [Fin] than the adversary, this card has -1 cost.\n\nDuelist Maneuver: +1[Riposte] for each other card in your dueling line. If you have three or more other cards in your dueling line, the adversary discards a card."},
  ["FAF-37"] = {name="Sanjay", type="Character", deck="Leader", faction="Castille", text="Sanjay's gambled combat cards have +1[rip].\n\nReaction: When Sanjay's challenge is refused • Collect a Renown from his location.\n\nCity Action:Target an opposing character • If their controller has fewer cards in hand than you, Sanjay issues an [Inf] challenge to that character."},
  ["FAF-38"] = {name="Damya Kahina", type="Character", deck="Approach", faction="Castille", text="City Action: Draw a card. Then, discard a card.\n\nCity Action: Your equipped character moves to this location. Then, destroy their attachment to draw cards equal to its printed cost, plus one. (The attachment must be destroyed to draw cards)"},
  ["FAF-39"] = {name="Íñigo Rocoso", type="Character", deck="Approach", faction="Castille", text="While Íñigo is equipped with a Weapon, he gains +1[Fin].\n\nGambling Technique: -2[Thrust] • The adversary discards a card. Then, if they have more cards in hand than you, en garde Íñigo. At the end of the round, move Íñigo Home. (Your combat card must have at least 2 [Thrust].)"},
  ["FAF-4"] = {name="Elena Agnelli", type="Character", deck="Approach", faction="Vodacce", text="Elena has +1[Fin] for each Sorcery in her dueling line.\n\nTechnique: If Elena's combat card is a Sorcery • +1[Parry] and wound the adversary."},
  ["FAF-40"] = {name="Soline el Gato", type="Character", deck="Approach", faction="Castille", text="City Reaction: After a character moves to this location • Move Soline to any City location.\n\nCity Action: Engage Soline • Pressure this location with [Fin]. You succeed even if tied. If successful, claim it or engage an opposing character."},
  ["FAF-41"] = {name="Proper Study", type="Scheme", deck="Approach", faction="Castille", text="Add a Renown to [docks] and [bazaar].\n\n---\n\nForced: At the end of Planning • Draw two cards, or three cards instead if you control an Academic. Then, discard an equal number of cards.\n\nCity Reaction: After you claim a location • Move a Renown from that location to a different location."},
  ["FAF-42"] = {name="When Least Expected ", type="Scheme", deck="Approach", faction="Castille", text="Add a Renown to [docks] and [forums]\n\n---\n\nCity Action: Engage your performer • They issue a [Fin] challenge to target opposing character. If your performer is a Duelist, it can only be refused by discarding a card."},
  ["FAF-43"] = {name="El Gato's Mask", type="Attachment", deck="Faction", faction="Castille", text="Equipped character gains Scoundrel.\n\nGambling Technique: If your participant has greater [Fin] than the adversary • Reveal two random cards from their hand. They choose and discard one revealed attachment. (If any were attachments.)"},
  ["FAF-44"] = {name="Torres Cloak", type="Attachment", deck="Faction", faction="Castille", text="Offhand\n\nMay only equip to your Duelist.\n\nReaction: When the equipped participant's adversary would resolve a Maneuver or Technique, engage this card • Cancel the effects unless they discard a card."},
  ["FAF-45"] = {name="Curious", type="Risk", deck="Faction", faction="Castille", text="Action: Wound your performer • Move them to an adjacent location controlled by an opponent.\n\nGambling Maneuver: Wound your participant • +2 [Riposte]."},
  ["FAF-46"] = {name="Passionate", type="Risk", deck="Faction", faction="Castille", text="Duelist Reaction: After your performer intervenes • En garde them.\n\nPirate Reaction: After your performer's challenge is accepted, if their adversary intervened • En garde your performer."},
  ["FAF-47"] = {name="Proper Drama", type="Risk", deck="Faction", faction="Castille", text="Scoundrel Maneuver: +1[Riposte]. If the adversary gambles during their next round, you choose their combat card.\n\nDuelist Maneuver: The adversary cannot gamble during their next round."},
  ["FAF-48"] = {name="Wily", type="Risk", deck="Faction", faction="Castille", text="If this card was gambled, it has -1 cost.\n\nScoundrel Maneuver: Move all threat from your participant to the adversary."},
  ["FAF-49"] = {name="Ekaterina Ilyanava", type="Character", deck="Leader", faction="Ussura", text="After Ekaterina's location is claimed, she may move to a different City location.\n\nWhen an opponent collects Renown from this location, they collect one fewer. (Remaining Renown stays).\n\nTechnique: +1 [Parry]. You may engage an Artifact equipped to Ekaterina for +2[Parry] instead."},
  ["FAF-5"] = {name="No Mercy", type="Scheme", deck="Approach", faction="Vodacce", text="Add a Renown to [Bazaar] and [Forums]\n\nPut a Gang, Crime, or Villainous card from your discard into your hand.\n\n---\n\nReaction: After your Red Hand's challenge is refused • Claim that location."},
  ["FAF-50"] = {name="Mōri Daichi", type="Character", deck="Approach", faction="Ussura", text="Daichi cannot refuse challenges issued by characters with greater [Com].\n\nWhen Daichi issues a challenge, characters with greater [Com] cannot refuse.\n\nGambling Technique: If Daichi's combat card is a Flourish or Sorcery • +1[Riposte]"},
  ["FAF-51"] = {name="Yepikhodov Yepikvidich", type="Character", deck="Approach", faction="Ussura", text="City Action: Move Yepikhodov to your Leader's location. Then, en garde your attachment there.\n\nYour other characters at this location gain: “Technique: Engage Yepikhodov's  attachment  • Copy the effects of a Technique on that attachment.”"},
  ["FAF-52"] = {name="Yevgeni", type="Character", deck="Approach", faction="Ussura", text="At the beginning of Dusk, you may look at the top three cards of the City Deck. If you do, sink one and replace the others in any order.\n\nGambling Technique: Look at your adversary's hand."},
  ["FAF-53"] = {name="Curry Favor", type="Scheme", deck="Approach", faction="Ussura", text="Add a Renown to two different locations.\n\n---\n\nCity Action: Spend a Renown • Claim your performer's location. Each opponent draws a card."},
  ["FAF-54"] = {name="No Steel, No Surrender", type="Scheme", deck="Approach", faction="Ussura", text="Add a Renown to [dock] and [forum].\n\n---\n\nCity Action: Wound your unequipped performer • Pressure their location with Resolve. If successful, wound target opposing character and move them Home."},
  ["FAF-55"] = {name="Syrneth Compass", type="Attachment", deck="Faction", faction="Ussura", text="City Action: Engage this card • Move the equipped character to a location where there is a Scion or an Artifact. (The Artifact may be available or equipped.)"},
  ["FAF-56"] = {name="Astute", type="Risk", deck="Faction", faction="Ussura", text="City Action: Target an opposing character • If their controller does not control this location, they claim it and you move a Renown from this location to another."},
  ["FAF-57"] = {name="Censure", type="Risk", deck="Faction", faction="Ussura", text="City Action: Engage your performer • Issue an [Inf] challenge to target opposing character. If the challenge is refused, claim your performer’s location."},
  ["FAF-58"] = {name="Courageous", type="Risk", deck="Faction", faction="Ussura", text="Duelist City Action: Target an opposing character • If their controller has more characters at this location than you, your performer issues a [Com] challenge to that character.\n\nGambling Maneuver: +1[Parry] and +1[Thrust] for each opposing character."},
  ["FAF-59"] = {name="Insightful", type="Risk", deck="Faction", faction="Ussura", text="Maneuver: Look at the top three cards of your adversary's deck. Reveal one and add its [par] or [thr] to this card. Replace them in any order. If your participant is an Academic, sink any of those cards instead of replacing them."},
  ["FAF-6"] = {name="Premonition", type="Scheme", deck="Approach", faction="Vodacce", text="Add a Renown to two different locations.\n\n---\n\nStrega Reaction: When your character at your performer's location is targeted by an opponent with more cards in hand than you • They must sink two cards from their hand. (When a card is played, it is removed from hand when it is announced, before choosing targets.)"},
  ["FAF-60"] = {name="Matushka's Song", type="Risk", deck="Faction", faction="Ussura", text="Sorcerer City Action: You may engage your performer, if you do, ignore all costs • Heal two wounds from another character at this location.\n\nGambling Maneuver: If you control a Sorcerer at this location • Heal two wounds from your participant."},
  ["FAF-61"] = {name="Burn like Mice", type="Scheme", deck="Approach", faction="Neutral", text="Add a Renown to [forums] and [bazaar].\n\n---\n\nHero City Action: Target an en garde non-Leader character at a player's Home • Move them to your performer's location.\n\nForced: At the end of High Drama, wound each character at each player's Home in an order of your choice."},
  ["FAF-62"] = {name="Deal with the Devil", type="Scheme", deck="Approach", faction="Neutral", text="Add a Renown to [forums] and [docks]\n\n---\n\nVillain City Action: Wound your performer • Muster one of your non-Undead, non-Mercenary characters from The Locker at this location. They gain Monster and Undead. At the end of Dusk, send them to The Locker."},
  ["FAF-63"] = {name="Smuggling Run", type="Scheme", deck="Approach", faction="Neutral", text="Add a Renown to [Bazaar} and [Docks]\n\n---\n\nWhen an opponent equips a card to a character opposing your Scoundrel, it gains +1 cost.\n\nScoundrel City Action: Move a Renown or an available attachment from your performer's location to a different City location."},
  ["FAF-64"] = {name="Harpoon", type="Attachment", deck="Faction", faction="Neutral", text="Gambling Technique: Engage this card • The adversary has -1[Fin], cannot be swapped, and cannot move for the remainder of the duel."},
  ["FAF-65"] = {name="Lodestone", type="Attachment", deck="Faction", faction="Neutral", text="Opponents' abilities cannot move the equipped character Home.\n\nCity Action: Sink this card• Move your performer Home."},
  ["FAF-66"] = {name="Shackles ", type="Attachment", deck="Faction", faction="Neutral", text="This card may only equip to an opposing character that has less [Fin] than your performer.\n\nEquipped character cannot move.\n\nForced: At the end of High Drama • Destroy this attachment."},
  ["FAF-67"] = {name="Ambitious", type="Risk", deck="Faction", faction="Neutral", text="Leader City Action: Wound your performer • If you control fewer locations than an opponent, pressure your performer's location with your choice of [Com], [Fin], or [Inf]. If successful, claim this location. Send this card to The Locker."},
  ["FAF-68"] = {name="Confusion", type="Risk", deck="Faction", faction="Neutral", text="City Reaction: After an opponent passes • They must move an en garde character from their Home to a City location."},
  ["FAF-69"] = {name="Hop on Board", type="Risk", deck="Faction", faction="Neutral", text="Maneuver: Swap your participant with your other character at this location.\n\nGambling Maneuver: Swap your participant with your other character at this location. Then +1[rip]."},
  ["FAF-7"] = {name="Matushka's Shears", type="Attachment", deck="Faction", faction="Vodacce", text="May only equip to your Strega.\n\nSorcerer City Reaction: When an opposing character is sent to The Locker, engage this card • Their controller wounds their Leader unless they sink two cards from their hand."},
  ["FAF-70"] = {name="Comforting", type="Risk", deck="Faction", faction="Neutral", text="Maneuver: Discard threat from your participant in excess of your adversary's stat value used for the duel. (Example: In an [Inf] duel, remove threat in excess of the adversary's [Inf])"},
  ["FAF-71"] = {name="Leverage", type="Risk", deck="Faction", faction="Neutral", text="This card has -1 cost if your Leader is a Villain or Pirate.\n\nCity Action: If this location is controlled by an opponent • Engage an opposing character."},
  ["FAF-72"] = {name="Sabotage", type="Risk", deck="Faction", faction="Neutral", text="City Action: Destroy all engaged attachments equipped to target opposing character. Then, engage each of their equipped attachments.\n\nManeuver: Destroy all engaged attachments equipped to the adversary."},
  ["FAF-73"] = {name="Victorious", type="Risk", deck="Faction", faction="Neutral", text="Forced: After your adversary is destroyed, if this card is in your dueling line • Draw a card.\n\nGambling Maneuver: +1[Thrust]."},
  ["FAF-8"] = {name="Arrogant", type="Risk", deck="Faction", faction="Vodacce", text="City Action: Your performer issues a [Com] challenge to target opposing character with equal or lower [Inf].\n\nGambling Maneuver: If your participant has more [Inf] than the adversary • +1[Riposte] and draw a card."},
  ["FAF-9"] = {name="Follow the Thread", type="Risk", deck="Faction", faction="Vodacce", text="Sorcerer Strega Action: Move your performer to an adjacent location where there is an enemy character or an available Mercenary.\n\nStrega Maneuver: -1[Thrust] • Wound the adversary."},
  ["TAC-1"] = {name="Andriana Dondolo", type="Character", deck="Approach", faction="Vodacce", text="Sorcerer Reaction: When target opposing non-Sorcerer intervenes or refuses a challenge • Wound them.\n\nSorcerer City Action: Discard a Sorcery and engage Andriana • Move target enemy non-Leader at a City location to Andriana's location. Then, she issues them a [Com] challenge."},
  ["TAC-10"] = {name="Twist of the Arcana", type="Risk", deck="Faction", faction="Vodacce", text="Sorcerer Strega City Action: Target two of your characters at your performer's location • Move up to two wounds between them."},
  ["TAC-11"] = {name="Katain DeWinter", type="Character", deck="Approach", faction="Eisen", text="Reaction: When Katain performs an ability on a Ranged card, discard a card • Copy the effects.\n\nTechnique: Engage Katain's equipped Ranged Weapon • +1[Parry]."},
  ["TAC-12"] = {name="Turais Dall", type="Character", deck="Approach", faction="Eisen", text="Berserker Reaction: When Turais issues a challenge, wound him • En garde him.\n\nBerserker Technique: Wound Turais • Remove all threat from him."},
  ["TAC-13"] = {name="Wilhelm Dünst", type="Character", deck="Approach", faction="Eisen", text="Wilhelm may only issue [Com] challenges to Villains, Sorcerers, and Monsters.\n\nCity Action: Discard a Relic or Faith card and target an opposing character • Wilhelm issues a [Com] challenge to them as if they were a Sorcerer."},
  ["TAC-14"] = {name="Kaspar's Occupation", type="Scheme", deck="Approach", faction="Eisen", text="Add or move a Renown to [Forums].\n\n---\n\nLeader City Action: Pressure your Leader's location with [Com]. You succeed even if tied. If successful, look at the top four cards of the City Deck. Discard any number of them and replace the rest in any order."},
  ["TAC-15"] = {name="Teeth of the Drachen", type="Scheme", deck="Approach", faction="Eisen", text="Add a Renown to two locations with no Renown.\n\n---\n\nCharacters at uncontrolled locations cannot intervene."},
  ["TAC-16"] = {name="Cross of the Martyrs", type="Attachment", deck="Faction", faction="Eisen", text="Cannot equip to Sorcerers.\n\nEquipped character gains Zealot.\n\nReaction: When an opponent targets your character at this location, wound your performer • That opponent targets your performer instead."},
  ["TAC-17"] = {name="Panzerhand", type="Attachment", deck="Faction", faction="Eisen", text="Offhand (Offhand attachments do not count against the limit of one Armor and one Weapon per character. Limit one attachment with Offhand per character.)\n\nReaction: When equipped participant's adversary announces a combat card • It has -1 [Riposte].\n\nTechnique: The adversary cannot activate Techniques during their next round."},
  ["TAC-18"] = {name="Divine Discipline", type="Risk", deck="Faction", faction="Eisen", text="Zealot City Action: Wound all characters at your performer's location.\n\nManeuver: Wound your participant • +X[Thrust] where X is the number of wounds on your participant.\""},
  ["TAC-19"] = {name="Trial of Faith", type="Risk", deck="Faction", faction="Eisen", text="City Reaction: When your performer's location is pressured with [Inf], wound them • Each player adds +1 to their total for each wound on their characters at this location. Then, if your performer is a Zealot, they may heal a wound."},
  ["TAC-2"] = {name="Elisabetta Bonora", type="Character", deck="Approach", faction="Vodacce", text="Sorcerer City Action: Look at the top three cards of target player's deck, put one or more of them into the discard pile, then replace the rest in any order.\n\nSorcerer Technique: -1[Thrust]."},
  ["TAC-20"] = {name="Yield", type="Risk", deck="Faction", faction="Eisen", text="City Action: Engage a Melee Weapon or Eisenfaust attachment equipped to your performer and target an opposing non-Leader • They may engage. If they do not, wound them."},
  ["TAC-21"] = {name="Grand Merchant Anghos", type="Character", deck="Approach", faction="Montaigne", text="City Reaction: When discarding cards to pay costs • One of your attachments discarded this way gains Wealth. (This card counts as two when discarded to pay costs. Send it to The Locker after paying costs.)\n\nTechnique: If Anghos has more [Inf] than the adversary • +1[Parry]."},
  ["TAC-22"] = {name="Lord Stranahan III", type="Character", deck="Approach", faction="Montaigne", text="When a challenge is issued to your Diplomat at this location, wound the challenging character.\n\nYour Musketeers at Stranahan's location gain \"\"Technique: Gain Lethal.\"\""},
  ["TAC-23"] = {name="Sir Jack Harding", type="Character", deck="Approach", faction="Montaigne", text="City Action: Move target opposing non-Leader to an adjacent City location with less Renown.\n\nTechnique: If the adversary is a Thug or Mercenary • +1[Thrust]."},
  ["TAC-24"] = {name="Oath of Vengeance", type="Scheme", deck="Approach", faction="Montaigne", text="Add two Renown to this card.\n\n---\n\nForced: After your Musketeer destroys their adversary • Collect a Renown from this card.\n\nForced: At the beginning of Dusk • Move each Renown on this card to different locations."},
  ["TAC-25"] = {name="Tea and Cakes", type="Scheme", deck="Approach", faction="Montaigne", text="Add a Renown to any location. Target opponent adds a Renown to any location.\n\n---\n\nDiplomat City Action: Target an opposing character with equal or lower [Inf] • Move them, your performer and a Renown from this location to the same adjacent location."},
  ["TAC-26"] = {name="Croc de Lion", type="Attachment", deck="Faction", faction="Montaigne", text="Offhand (Offhand attachments do not count against the limit of one Armor and one Weapon per character. Limit one attachment with Offhand per character.)\n\nDuelist Technique: Engage target attachment equipped to the adversary.\n\nDuelist Technique: Destroy target engaged attachment equipped to the adversary."},
  ["TAC-27"] = {name="Éventail", type="Attachment", deck="Faction", faction="Montaigne", text="May only equip to your Diplomat.\n\nWhile equipped character is en garde, they gain +1[Inf]. (While performing the Parley Reaction or the Claim Action, engage costs occur first.)"},
  ["TAC-28"] = {name="Battle of Wits", type="Risk", deck="Faction", faction="Montaigne", text="Diplomat City Action: Your performer issues a [Inf] challenge to target opposing character with 1[Inf] or more.\n\nManeuver: +X[Thrust] where X is equal to your participant's [Inf]. If your participant is a Diplomat, gain Lethal."},
  ["TAC-29"] = {name="Diplomatic Immunity", type="Risk", deck="Faction", faction="Montaigne", text="Diplomat Action: If you control more Diplomats at your performer's location than the amount of Renown there • Claim that location.\n\nManeuver +1[Riposte] for each Diplomat you control at this location."},
  ["TAC-3"] = {name="Mourad", type="Character", deck="Approach", faction="Vodacce", text="Sorcerer abilities cannot target Mourad.\n\nReaction: When your Strega at this location is challenged • Mourad may intervene even while engaged.\n\nTechnique: If Mourad's combat card is a Sorcery and you control a Strega at his location • Draw a card."},
  ["TAC-30"] = {name="Fratarnité!", type="Risk", deck="Faction", faction="Montaigne", text="Reaction: When an ability is announced • Your character gains Musketeer until the action resolves. (Announcing occurs before performers and targets are chosen.)\n\nReaction: When a challenge is issued • Your character gains Musketeer until the action resolves. (Any subsequent duel is part of the challenge action.)"},
  ["TAC-31"] = {name="Lucas Martinez - Doomed", type="Character", deck="Approach", faction="Castille", text="Forced: After Lucas Martinez “Doomed” is mustered, send Lucas Martinez “Damned” to The Locker from out of play.\nForced: After this card is sent to The Locker •  Muster Lucas Martinez  \"Damned\" at that location from The Locker."},
  ["TAC-32"] = {name="Lucas Martinez - Damned", type="Character", deck="Approach", faction="Castille", text="Lucas Martinez \"Damned\" cannot be in an Approach deck and can only be mustered from The Locker instead.\nReaction: After Lucas musters, put your risk from The Locker into your hand.\nForced: At the beginning of Dawn, destroy Lucas."},
  ["TAC-33"] = {name="\"Prima\" Rosa", type="Character", deck="Approach", faction="Castille", text="When Rosa's combat card is a Revelry, gain Lethal.\n\nCity Action: Move target adjacent City Card to Rosa's Location.\nReaction: After a character moves to Rosa's location • Their controller discards a card."},
  ["TAC-34"] = {name="Torvo Espada", type="Character", deck="Approach", faction="Castille", text="City Action: Target an opposing character with 2[Com] or more • They may issue a [Com] challenge to Torvo. If they do not, draw a card. If they do, other characters cannot intervene.\nTechnique: +1[Parry]. If there is an Aldana card in Torvo's dueling line, +1[Riposte] instead."},
  ["TAC-35"] = {name="Castillian Caper", type="Scheme", deck="Approach", faction="Castille", text="Add Renown to 2 different with none.\n\nScoundrel Action: Performer is opposed . Pressure Finesse +1/controlled Scoundrel to collect 1 renown from there."},
  ["TAC-36"] = {name="Rumours of the Crimson Roger", type="Scheme", deck="Approach", faction="Castille", text="Add 2 Renown to docks.\n\nPirate Action: Target opposing non-Pirate . Move target home unless opponent discards 1.\nPirate Action, performer adjacent to docks . move them there."},
  ["TAC-37"] = {name="Mysta", type="Attachment", deck="Faction", faction="Castille", text="Forced: When this card would be put in the discard pile, sink it instead.\nTechnique: The adversary cannot gamble during their next round.\nReaction: After an opposing character issues a challenge • Equip this card to your character at this location."},
  ["TAC-38"] = {name="Gold or Steel", type="Risk", deck="Faction", faction="Castille", text="Pirate Maneuver:  If your participant has more [Com] than the adversary • Draw a card unless the adversary suffers a wound.\nDuelist Maneuver: If your participant has more [Fin] than the adversary • Draw a card unless the adversary suffers a wound."},
  ["TAC-39"] = {name="Raise the Stakes", type="Risk", deck="Faction", faction="Castille", text="Reaction:  When the adversary announces their combat card • Add a threat to both participants.\nManeuver: At the end of the round • Add a threat to both participants."},
  ["TAC-4"] = {name="Crash the Party", type="Scheme", deck="Approach", faction="Vodacce", text="Add a Renown to [Docks] and [Bazaar]\n\n---\n\nCity Reaction: When an opponent initiates a pressure • Move your adjacent en garde performer to the pressured location. If the opponent's pressure succeeds, draw a card."},
  ["TAC-40"] = {name="Siesta", type="Risk", deck="Faction", faction="Castille", text="City Action: Move your performer Home engaged. Then, they heal a wound."},
  ["TAC-41"] = {name="You Cheated!", type="Risk", deck="Faction", faction="Castille", text="Scoundrel Maneuver: This duel becomes a duel of [Fin] for the remainder of the duel."},
  ["TAC-42"] = {name="Ivy", type="Character", deck="Approach", faction="Ussura", text="When your participant at this location gambles, they reveal an additional card.\n\nSorcerer City Reaction: After your participant reveals their gambled cards • Put a revealed Sorcery into your hand. (Before choosing one as a combat card.)"},
  ["TAC-43"] = {name="Miyato and Ota", type="Character", deck="Approach", faction="Ussura", text="Technique: After Miyato and Ota perform a Maneuver • Copy the effects. Send that combat card to The Locker. Usable once per day.\n\nTechnique: Choose a Flourish in your discard pile and place it on top of your deck."},
  ["TAC-44"] = {name="Solomonia Saboruvya", type="Character", deck="Approach", faction="Ussura", text="While [Forums] is uncontrolled, Solomonia cannot be challenged.\n\nWhile Solomonia is at [Forums], add +1 to your total during [Inf] pressures at adjacent locations."},
  ["TAC-45"] = {name="Path to Poluchatel", type="Scheme", deck="Approach", faction="Ussura", text="Choose one of the outermost locations. Add a Renown to two other locations. Place this card on the chosen location.\n\n---\n\n---\n\nSorcerer City Action: If your performer is at the chosen location • Pressure it with [Inf]. If successful, search your deck for a Dar Matushki or Poluchatel card, reveal it, and put it into your hand. (Shuffle your deck.)"},
  ["TAC-46"] = {name="Winter's Winds", type="Scheme", deck="Approach", faction="Ussura", text="Add a Renown to any location. Then, you may add a Renown to a different location.\n\n---\n\nAfter any character enters play during High Drama, engage them. (Characters enter play when they are recruited, played from hand, or mustered.)"},
  ["TAC-47"] = {name="Temnota", type="Attachment", deck="Faction", faction="Ussura", text="Equipped character gains Sorcerer.\n\nCity Action: Target an available attachment at this location • Send it to The Locker. Then, if it was an Artifact, add a Renown to this location. (Only City Cards are available.)"},
  ["TAC-48"] = {name="Blood Like Winter", type="Risk", deck="Faction", faction="Ussura", text="City Reaction: When your opponent's risk targets your performer • Pressure your performer's location with [Com]. If successful, cancel the effects."},
  ["TAC-49"] = {name="Justice Served Cold", type="Risk", deck="Faction", faction="Ussura", text="City Action: Your performer issues a [com] challenge to target opposing Mercenary or Thug.\n\nManeuver: If the adversary is a Mercenary or Thug • +1[Riposte]."},
  ["TAC-5"] = {name="Decipher the Strands", type="Scheme", deck="Approach", faction="Vodacce", text="Add a Renown to any location. Then, add a Renown to a location with no Renown.\n\nLook at the top three cards of an opponent's deck and an additional card for each Strega you control. Sink one or more of those cards and replace the rest in any order."},
  ["TAC-50"] = {name="Ussuran Intrigue", type="Risk", deck="Faction", faction="Ussura", text="City Reaction: When any player moves or adds any amount of Renown to any location • Pressure your performer's location with [Inf]. You succeed even if tied. If successful, move one of that Renown to their location instead. (Even during Planning.)"},
  ["TAC-51"] = {name="Voice of the Gods", type="Risk", deck="Faction", faction="Ussura", text="Sorcerer City Action: Engage your performer • En garde target character at your performer's location. Send this card to The Locker."},
  ["TAC-52"] = {name="Gutter Full of Roses", type="Scheme", deck="Approach", faction="Neutral", text="Add a Renown to [Bazaar]. Then, move a Renown to [Bazaar].\n\n---\n\nForced: When a player's adversary is destroyed during a duel at [Bazaar] • That player collects a Renown from [Bazaar]. (This Forced ability activates for any player.)"},
  ["TAC-53"] = {name="Under Cover of Night", type="Scheme", deck="Approach", faction="Neutral", text="Add a Renown to [Docks].\n\n---\n\nCity Reaction: At the beginning of Dusk • Your performer does not move Home during Dusk. Then, send up to one card from each discard pile to The Locker."},
  ["TAC-54"] = {name="Concealed Flintlock", type="Attachment", deck="Faction", faction="Neutral", text="Offhand (Offhand attachments do not count against the limit of one Armor and one Weapon per character. Limit one attachment with Offhand per character.)\n\nManeuver: Equip this card to your participant from your dueling line. If they have 1[Com] or less, draw a card.\n\nTechnique: Your adversary may suffer a wound. If they do not, +1[Parry]."},
  ["TAC-55"] = {name="Dame of Swords", type="Attachment", deck="Faction", faction="Neutral", text="Technique: Copy the effects of a Technique on your participant or one of their attachments. Sink this card."},
  ["TAC-56"] = {name="Main Gauche", type="Attachment", deck="Faction", faction="Neutral", text="\"Offhand (Offhand attachments do not count against the limit of one Armor and one Weapon per character. Limit one attachment with Offhand per character.)\n\nMay only equip to your Duelist.\n\nTechnique: +1[Parry]. If your participant has 3[fin] or more, +1[Riposte] instead."},
  ["TAC-57"] = {name="Collateral Damage", type="Risk", deck="Faction", faction="Neutral", text="Maneuver: Wound a character at this location that is not a participant in the duel. If they have Brute, wound them again."},
  ["TAC-58"] = {name="Heroic Intervention", type="Risk", deck="Faction", faction="Neutral", text="If your performer is a Hero or Knight, this card has -1 cost.\n\nReaction: After a challenge is issued, engage your adjacent performer • Move them to that location and they intervene."},
  ["TAC-59"] = {name="Quick Reflexes", type="Risk", deck="Faction", faction="Neutral", text="Reaction: When an opponent's ability wounds your character • Ignore that wound. (The wound is not taken.)\n\nManeuver: If your participant has 3[Fin] or more • +1[Riposte]."},
  ["TAC-6"] = {name="The Red Sceptre", type="Attachment", deck="Faction", faction="Vodacce", text="May only equip to your Red Hand.\n\nTechnique: Wound your other character at this location and engage this card • +1[Parry]."},
  ["TAC-60"] = {name="Relentless", type="Risk", deck="Faction", faction="Neutral", text="Reaction: When your challenge is refused, wound your challenger • Wound the refusing character.\n\nReaction: When the duel would end, wound your participant • Wound your opposing adversary.\""},
  ["TAC-61"] = {name="Unsanctioned Duel", type="Risk", deck="Faction", faction="Neutral", text="Duelist City Action: Engage your performer • Issue an unrefusable [Com] challenge to target opposing non-Leader. At the start of the first round of the following duel, add a threat to both participants. These effects cannot be cancelled."},
  ["TAC-7"] = {name="Arson", type="Risk", deck="Faction", faction="Vodacce", text="Red Hand City Action: Wound your performer • Remove a Renown and discard target available City card from your performer's location."},
  ["TAC-8"] = {name="Fate's Kiss", type="Risk", deck="Faction", faction="Vodacce", text="Sorcerer Strega Action: Choose a risk from your discard pile and place it face-down under target opposing character • When that character is destroyed, put that risk into your hand."},
  ["TAC-9"] = {name="Murder", type="Risk", deck="Faction", faction="Vodacce", text="Thug Maneuver: Wound adversary.\n\nDuelist Maneuver: Wound adversary.\n\nSpy Maneuver: Wound adversary."},
}

